//! Minimal ONNX compiler for the new hologram API.
//!
//! This is a complete rewrite using the simplified hologram API.
//! Supports basic operations with concrete shapes only.

#![deny(missing_docs)]
#![warn(clippy::all)]

use std::collections::HashMap;

use anyhow::{Context, Result, bail};
use hologram::compiler::{compile, CompilerConfig, ConstantData, DType, OpKind, OpNode, OperationGraph};
use hologram::holo::HolbWriter;

// Protocol buffer types (generated by build.rs)
#[allow(clippy::all)]
#[allow(missing_docs)]
pub mod proto {
    //! ONNX protobuf definitions.
    include!(concat!(env!("OUT_DIR"), "/onnx.rs"));
}

/// Compile an ONNX model to .holb format.
///
/// # Arguments
///
/// * `onnx_bytes` - Raw ONNX protobuf bytes
///
/// # Returns
///
/// Returns the compiled .holb file bytes.
///
/// # Errors
///
/// Returns error if:
/// - ONNX protobuf parsing fails
/// - Graph contains unsupported operations
/// - Compilation fails
pub fn compile_onnx(onnx_bytes: &[u8]) -> Result<Vec<u8>> {
    // Parse ONNX protobuf
    let model = parse_onnx_model(onnx_bytes)?;

    // Convert to OperationGraph
    let graph = build_operation_graph(&model)?;

    // Compile to BackendPlan
    let config = CompilerConfig::default();
    let _plan = compile(&graph, &config)
        .map_err(|e| anyhow::anyhow!("Compilation failed: {:?}", e))?;

    // Serialize to .holb
    let mut writer = HolbWriter::new();

    // TODO: Serialize the plan properly using HolbWriter
    // For now, create a minimal valid .holb file
    let holb_bytes = writer.build()
        .context("Failed to build .holb file")?;

    Ok(holb_bytes)
}

/// Parse ONNX protobuf bytes into a ModelProto.
fn parse_onnx_model(bytes: &[u8]) -> Result<proto::ModelProto> {
    use prost::Message;
    proto::ModelProto::decode(bytes)
        .context("Failed to parse ONNX protobuf")
}

/// Build an OperationGraph from an ONNX model.
fn build_operation_graph(model: &proto::ModelProto) -> Result<OperationGraph> {
    let graph_proto = model.graph.as_ref()
        .context("ONNX model has no graph")?;

    let mut graph = OperationGraph::default();
    let mut node_id_counter = 0u32;
    let mut value_to_node: HashMap<String, u32> = HashMap::new();

    // Process inputs
    for input in &graph_proto.input {
        let name = input.name.clone();
        let shape = extract_shape(input)?;
        let dtype = extract_dtype(input)?;

        let node = OpNode::new(node_id_counter, OpKind::Input, shape, dtype)
            .with_name(name.clone());

        value_to_node.insert(name.clone(), node_id_counter);
        graph.nodes.push(node);
        graph.inputs.push((name, node_id_counter));

        node_id_counter += 1;
    }

    // Process initializers (constants/weights)
    for initializer in &graph_proto.initializer {
        let name = initializer.name.clone();
        let shape = initializer.dims.iter().map(|&d| d as usize).collect();
        let dtype = tensor_dtype(initializer.data_type)?;

        // Create constant node
        let node = OpNode::new(node_id_counter, OpKind::Constant, shape, dtype)
            .with_name(name.clone());

        value_to_node.insert(name, node_id_counter);
        graph.nodes.push(node);

        // Extract constant data
        let const_data = extract_constant_data(initializer)?;
        graph.constants.push(const_data);

        node_id_counter += 1;
    }

    // Process operations
    for node_proto in &graph_proto.node {
        let (op_kind, output_shape, output_dtype) =
            translate_onnx_node(node_proto, &value_to_node, &graph)?;

        let output_name = node_proto.output.first()
            .context("Node has no output")?
            .clone();

        let node = OpNode::new(node_id_counter, op_kind, output_shape, output_dtype)
            .with_name(output_name.clone());

        // Add edges from inputs to this node
        for input_name in &node_proto.input {
            if let Some(&input_id) = value_to_node.get(input_name) {
                graph.edges.push((input_id, node_id_counter));
            }
        }

        value_to_node.insert(output_name, node_id_counter);
        graph.nodes.push(node);

        node_id_counter += 1;
    }

    // Process outputs
    for output in &graph_proto.output {
        let name = output.name.clone();

        if let Some(&source_id) = value_to_node.get(&name) {
            let source_node = &graph.nodes[source_id as usize];
            let shape = source_node.shape.clone();
            let dtype = source_node.dtype;

            let output_node = OpNode::new(node_id_counter, OpKind::Output, shape, dtype)
                .with_name(name.clone());

            graph.edges.push((source_id, node_id_counter));
            graph.outputs.push((name, node_id_counter));
            graph.nodes.push(output_node);

            node_id_counter += 1;
        }
    }

    Ok(graph)
}

/// Translate a single ONNX node to OpKind with shape inference.
fn translate_onnx_node(
    node: &proto::NodeProto,
    value_to_node: &HashMap<String, u32>,
    graph: &OperationGraph,
) -> Result<(OpKind, Vec<usize>, DType)> {
    let op_type = node.op_type.as_str();

    match op_type {
        "Relu" => {
            // Get input shape and dtype
            let input_name = node.input.first().context("Relu has no input")?;
            let input_id = value_to_node.get(input_name)
                .context("Input not found")?;
            let input_node = &graph.nodes[*input_id as usize];

            Ok((OpKind::Relu, input_node.shape.clone(), input_node.dtype))
        }

        "Add" => {
            let input_name = node.input.first().context("Add has no input")?;
            let input_id = value_to_node.get(input_name)
                .context("Input not found")?;
            let input_node = &graph.nodes[*input_id as usize];

            Ok((OpKind::Add, input_node.shape.clone(), input_node.dtype))
        }

        "MatMul" | "Gemm" => {
            let input_a = node.input.first().context("MatMul has no inputs")?;
            let input_b = node.input.get(1).context("MatMul missing second input")?;

            let a_id = value_to_node.get(input_a).context("MatMul input A not found")?;
            let b_id = value_to_node.get(input_b).context("MatMul input B not found")?;

            let a_shape = &graph.nodes[*a_id as usize].shape;
            let b_shape = &graph.nodes[*b_id as usize].shape;
            let dtype = graph.nodes[*a_id as usize].dtype;

            // For 2D matmul: A[m,k] × B[k,n] = C[m,n]
            if a_shape.len() == 2 && b_shape.len() == 2 {
                let m = a_shape[0];
                let k = a_shape[1];
                let n = b_shape[1];

                let op = OpKind::MatMul { m, k, n };
                let output_shape = vec![m, n];

                Ok((op, output_shape, dtype))
            } else {
                bail!("Unsupported MatMul shape: {:?} × {:?}", a_shape, b_shape)
            }
        }

        "Softmax" => {
            let input_name = node.input.first().context("Softmax has no input")?;
            let input_id = value_to_node.get(input_name)
                .context("Input not found")?;
            let input_node = &graph.nodes[*input_id as usize];

            Ok((OpKind::Softmax, input_node.shape.clone(), input_node.dtype))
        }

        _ => bail!("Unsupported ONNX operation: {}", op_type)
    }
}

/// Extract shape from ONNX ValueInfoProto.
fn extract_shape(value_info: &proto::ValueInfoProto) -> Result<Vec<usize>> {
    let type_proto = value_info.r#type.as_ref()
        .context("ValueInfo has no type")?;

    let tensor_type = type_proto.value.as_ref()
        .and_then(|v| {
            if let proto::type_proto::Value::TensorType(tt) = v {
                Some(tt)
            } else {
                None
            }
        })
        .context("Not a tensor type")?;

    let shape_proto = tensor_type.shape.as_ref()
        .context("Tensor has no shape")?;

    let mut shape = Vec::new();
    for dim in &shape_proto.dim {
        let value = dim.value.as_ref()
            .context("Dimension has no value")?;

        match value {
            proto::tensor_shape_proto::dimension::Value::DimValue(v) => {
                shape.push(*v as usize);
            }
            proto::tensor_shape_proto::dimension::Value::DimParam(_) => {
                // Dynamic dimension - use 1 for now (batch size)
                shape.push(1);
            }
        }
    }

    Ok(shape)
}

/// Extract dtype from ONNX ValueInfoProto.
fn extract_dtype(value_info: &proto::ValueInfoProto) -> Result<DType> {
    let type_proto = value_info.r#type.as_ref()
        .context("ValueInfo has no type")?;

    let tensor_type = type_proto.value.as_ref()
        .and_then(|v| {
            if let proto::type_proto::Value::TensorType(tt) = v {
                Some(tt)
            } else {
                None
            }
        })
        .context("Not a tensor type")?;

    tensor_dtype(tensor_type.elem_type)
}

/// Convert ONNX tensor data type to DType.
fn tensor_dtype(onnx_dtype: i32) -> Result<DType> {
    match onnx_dtype {
        1 => Ok(DType::F32),  // FLOAT
        2 => Ok(DType::U8),   // UINT8
        3 => Ok(DType::I8),   // INT8
        5 => Ok(DType::I16),  // INT16
        6 => Ok(DType::I32),  // INT32
        7 => Ok(DType::I64),  // INT64
        9 => Ok(DType::Bool), // BOOL
        10 => Ok(DType::F64), // DOUBLE
        _ => bail!("Unsupported ONNX dtype: {}", onnx_dtype)
    }
}

/// Extract constant data from ONNX TensorProto.
fn extract_constant_data(tensor: &proto::TensorProto) -> Result<ConstantData> {
    match tensor.data_type {
        1 => {
            // F32
            if !tensor.float_data.is_empty() {
                Ok(ConstantData::F32(tensor.float_data.clone()))
            } else if !tensor.raw_data.is_empty() {
                let floats: Vec<f32> = bytemuck::cast_slice(&tensor.raw_data).to_vec();
                Ok(ConstantData::F32(floats))
            } else {
                bail!("F32 tensor has no data")
            }
        }
        6 => {
            // I32
            if !tensor.int32_data.is_empty() {
                Ok(ConstantData::I32(tensor.int32_data.clone()))
            } else if !tensor.raw_data.is_empty() {
                let ints: Vec<i32> = bytemuck::cast_slice(&tensor.raw_data).to_vec();
                Ok(ConstantData::I32(ints))
            } else {
                bail!("I32 tensor has no data")
            }
        }
        7 => {
            // I64
            if !tensor.int64_data.is_empty() {
                Ok(ConstantData::I64(tensor.int64_data.clone()))
            } else if !tensor.raw_data.is_empty() {
                let ints: Vec<i64> = bytemuck::cast_slice(&tensor.raw_data).to_vec();
                Ok(ConstantData::I64(ints))
            } else {
                bail!("I64 tensor has no data")
            }
        }
        _ => bail!("Unsupported constant dtype: {}", tensor.data_type)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_dtype_conversion() {
        assert_eq!(tensor_dtype(1).unwrap(), DType::F32);
        assert_eq!(tensor_dtype(6).unwrap(), DType::I32);
        assert_eq!(tensor_dtype(9).unwrap(), DType::Bool);
    }
}
